import{_ as s,o as i,c as e,ae as l}from"./chunks/framework.C7FLYIpo.js";const g=JSON.parse('{"title":"커뮤니티 플러그인","description":"커뮤니티에서 유지 관리하는 OpenClaw 플러그인: 탐색, 설치, 자신의 플러그인 제출하기","frontmatter":{"title":"커뮤니티 플러그인","description":"커뮤니티에서 유지 관리하는 OpenClaw 플러그인: 탐색, 설치, 자신의 플러그인 제출하기"},"headers":[],"relativePath":"plugins/community.md","filePath":"plugins/community.md","lastUpdated":null}'),t={name:"plugins/community.md"};function n(p,a,o,h,r,c){return i(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="커뮤니티-플러그인" tabindex="-1">커뮤니티 플러그인 <a class="header-anchor" href="#커뮤니티-플러그인" aria-label="Permalink to &quot;커뮤니티 플러그인&quot;">​</a></h1><p>커뮤니티 플러그인은 새로운 채널, 도구, 프로바이더, 또는 기타 기능으로 OpenClaw를 확장하는 서드파티 패키지입니다. 커뮤니티에서 빌드하고 유지 관리하며, <a href="/openclaw-docs-ko/tools/clawhub">ClawHub</a> 또는 npm에 게시되고, 단일 명령으로 설치할 수 있습니다.</p><p>ClawHub는 커뮤니티 플러그인의 표준 검색 표면입니다. 검색 가능성을 위해 플러그인을 추가하는 문서 전용 PR을 열지 마십시오; 대신 ClawHub에 게시하십시오.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">package-name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&amp;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>OpenClaw는 먼저 ClawHub를 확인하고 자동으로 npm으로 폴백합니다.</p><h2 id="목록에-있는-플러그인" tabindex="-1">목록에 있는 플러그인 <a class="header-anchor" href="#목록에-있는-플러그인" aria-label="Permalink to &quot;목록에 있는 플러그인&quot;">​</a></h2><h3 id="codex-app-server-bridge" tabindex="-1">Codex App Server Bridge <a class="header-anchor" href="#codex-app-server-bridge" aria-label="Permalink to &quot;Codex App Server Bridge&quot;">​</a></h3><p>Codex App Server 대화를 위한 독립적인 OpenClaw 브리지입니다. 채팅을 Codex 스레드에 바인딩하고 일반 텍스트로 대화하며 재개, 계획, 검토, 모델 선택, 압축 등을 위한 채팅 네이티브 명령으로 제어합니다.</p><ul><li><strong>npm:</strong> <code>openclaw-codex-app-server</code></li><li><strong>저장소:</strong> <a href="https://github.com/pwrdrvr/openclaw-codex-app-server" target="_blank" rel="noreferrer">github.com/pwrdrvr/openclaw-codex-app-server</a></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw-codex-app-server</span></span></code></pre></div><h3 id="dingtalk" tabindex="-1">DingTalk <a class="header-anchor" href="#dingtalk" aria-label="Permalink to &quot;DingTalk&quot;">​</a></h3><p>스트림 모드를 사용하는 엔터프라이즈 로봇 통합입니다. 모든 DingTalk 클라이언트를 통해 텍스트, 이미지, 파일 메시지를 지원합니다.</p><ul><li><strong>npm:</strong> <code>@largezhou/ddingtalk</code></li><li><strong>저장소:</strong> <a href="https://github.com/largezhou/openclaw-dingtalk" target="_blank" rel="noreferrer">github.com/largezhou/openclaw-dingtalk</a></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @largezhou/ddingtalk</span></span></code></pre></div><h3 id="lossless-claw-lcm" tabindex="-1">Lossless Claw (LCM) <a class="header-anchor" href="#lossless-claw-lcm" aria-label="Permalink to &quot;Lossless Claw (LCM)&quot;">​</a></h3><p>OpenClaw용 무손실 컨텍스트 관리 플러그인입니다. DAG 기반 대화 요약과 증분 압축으로 전체 컨텍스트 충실도를 유지하면서 토큰 사용량을 줄입니다.</p><ul><li><strong>npm:</strong> <code>@martian-engineering/lossless-claw</code></li><li><strong>저장소:</strong> <a href="https://github.com/Martian-Engineering/lossless-claw" target="_blank" rel="noreferrer">github.com/Martian-Engineering/lossless-claw</a></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @martian-engineering/lossless-claw</span></span></code></pre></div><h3 id="opik" tabindex="-1">Opik <a class="header-anchor" href="#opik" aria-label="Permalink to &quot;Opik&quot;">​</a></h3><p>에이전트 트레이스를 Opik으로 내보내는 공식 플러그인입니다. 에이전트 동작, 비용, 토큰, 오류 등을 모니터링합니다.</p><ul><li><strong>npm:</strong> <code>@opik/opik-openclaw</code></li><li><strong>저장소:</strong> <a href="https://github.com/comet-ml/opik-openclaw" target="_blank" rel="noreferrer">github.com/comet-ml/opik-openclaw</a></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @opik/opik-openclaw</span></span></code></pre></div><h3 id="qqbot" tabindex="-1">QQbot <a class="header-anchor" href="#qqbot" aria-label="Permalink to &quot;QQbot&quot;">​</a></h3><p>QQ Bot API를 통해 OpenClaw를 QQ에 연결합니다. 개인 채팅, 그룹 언급, 채널 메시지, 음성, 이미지, 동영상, 파일을 포함한 리치 미디어를 지원합니다.</p><ul><li><strong>npm:</strong> <code>@tencent-connect/openclaw-qqbot</code></li><li><strong>저장소:</strong> <a href="https://github.com/tencent-connect/openclaw-qqbot" target="_blank" rel="noreferrer">github.com/tencent-connect/openclaw-qqbot</a></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @tencent-connect/openclaw-qqbot</span></span></code></pre></div><h3 id="wecom" tabindex="-1">wecom <a class="header-anchor" href="#wecom" aria-label="Permalink to &quot;wecom&quot;">​</a></h3><p>Tencent WeCom 팀의 OpenClaw용 WeCom 채널 플러그인입니다. WeCom Bot WebSocket 지속 연결로 구동되며, 직접 메시지 및 그룹 채팅, 스트리밍 답장, 능동적 메시징, 이미지/파일 처리, 마크다운 형식, 내장 액세스 제어, 문서/회의/메시징 스킬을 지원합니다.</p><ul><li><strong>npm:</strong> <code>@wecom/wecom-openclaw-plugin</code></li><li><strong>저장소:</strong> <a href="https://github.com/WecomTeam/wecom-openclaw-plugin" target="_blank" rel="noreferrer">github.com/WecomTeam/wecom-openclaw-plugin</a></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @wecom/wecom-openclaw-plugin</span></span></code></pre></div><h2 id="플러그인-제출하기" tabindex="-1">플러그인 제출하기 <a class="header-anchor" href="#플러그인-제출하기" aria-label="Permalink to &quot;플러그인 제출하기&quot;">​</a></h2><p>유용하고 문서화되어 있으며 안전하게 운영할 수 있는 커뮤니티 플러그인을 환영합니다.</p><ol><li><p><strong>ClawHub 또는 npm에 게시하기</strong></p><p>플러그인은 <code>openclaw plugins install \\&amp;lt;package-name\\&amp;gt;</code>으로 설치할 수 있어야 합니다. <a href="/openclaw-docs-ko/tools/clawhub">ClawHub</a>(권장) 또는 npm에 게시하십시오. 전체 가이드는 <a href="/openclaw-docs-ko/plugins/building-plugins">플러그인 빌드하기</a>를 참조하십시오.</p></li><li><p><strong>GitHub에 호스팅하기</strong></p></li></ol><p>소스 코드는 설정 문서와 이슈 트래커가 있는 공개 저장소에 있어야 합니다.</p><ol start="3"><li><strong>소스 문서 변경에만 문서 PR 사용하기</strong></li></ol><p>플러그인을 검색 가능하게 만들기 위한 문서 PR은 필요하지 않습니다. 대신 ClawHub에 게시하십시오.</p><pre><code>   OpenClaw의 소스 문서에 실제 콘텐츠 변경이 필요한 경우에만 문서 PR을 여십시오.
   예를 들어, 설치 안내를 수정하거나 기본 문서 세트에 포함되어야 하는
   크로스-저장소 문서를 추가하는 경우입니다.
</code></pre><h2 id="품질-기준" tabindex="-1">품질 기준 <a class="header-anchor" href="#품질-기준" aria-label="Permalink to &quot;품질 기준&quot;">​</a></h2><table tabindex="0"><thead><tr><th>요구사항</th><th>이유</th></tr></thead><tbody><tr><td>ClawHub 또는 npm에 게시됨</td><td>사용자가 <code>openclaw plugins install</code>을 사용할 수 있어야 합니다</td></tr><tr><td>공개 GitHub 저장소</td><td>소스 검토, 이슈 추적, 투명성</td></tr><tr><td>설정 및 사용 문서</td><td>사용자가 구성 방법을 알아야 합니다</td></tr><tr><td>활발한 유지 관리</td><td>최근 업데이트 또는 이슈에 대한 응답</td></tr></tbody></table><p>낮은 품질의 래퍼, 불명확한 소유권, 또는 유지 관리되지 않는 패키지는 거부될 수 있습니다.</p><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools/plugin">플러그인 설치 및 구성</a> — 플러그인 설치 방법</li><li><a href="/openclaw-docs-ko/plugins/building-plugins">플러그인 빌드하기</a> — 직접 만들기</li><li><a href="/openclaw-docs-ko/plugins/manifest">플러그인 매니페스트</a> — 매니페스트 스키마</li></ul>`,42)])])}const k=s(t,[["render",n]]);export{g as __pageData,k as default};
